namespace Contoso.Orders.Tests;

[TestClass]
public sealed class OrderServiceTests
{
    private OrderService _service = null!;

    [TestInitialize]
    public void Setup()
    {
        _service = new OrderService();
    }

    private static List<OrderItem> CreateItems(params (string Name, decimal Price, int Qty)[] items) =>
        items.Select(i => new OrderItem { ProductName = i.Name, Price = i.Price, Quantity = i.Qty }).ToList();

    // ── CreateOrder ─────────────────────────────────────────────────

    [TestMethod]
    public void CreateOrder_WithValidItems_ReturnsOrderWithCorrectCustomerId()
    {
        var items = CreateItems(("Widget", 9.99m, 1));

        var order = _service.CreateOrder("cust-1", items);

        Assert.AreEqual("cust-1", order.CustomerId);
    }

    [TestMethod]
    public void CreateOrder_WithMultipleItems_CalculatesTotalCorrectly()
    {
        var items = CreateItems(("A", 10.00m, 2), ("B", 5.50m, 3));

        var order = _service.CreateOrder("cust-1", items);

        Assert.AreEqual(10.00m * 2 + 5.50m * 3, order.Total);
    }

    [TestMethod]
    public void CreateOrder_AssignsNonEmptyId()
    {
        var items = CreateItems(("Widget", 1.00m, 1));

        var order = _service.CreateOrder("cust-1", items);

        Assert.IsFalse(string.IsNullOrWhiteSpace(order.Id));
    }

    [TestMethod]
    public void CreateOrder_AssignsUniqueIds()
    {
        var items = CreateItems(("Widget", 1.00m, 1));

        var order1 = _service.CreateOrder("cust-1", items);
        var order2 = _service.CreateOrder("cust-1", items);

        Assert.AreNotEqual(order1.Id, order2.Id);
    }

    [TestMethod]
    public void CreateOrder_SetsCreatedAtToRecentUtcTime()
    {
        var before = DateTime.UtcNow;
        var items = CreateItems(("Widget", 1.00m, 1));

        var order = _service.CreateOrder("cust-1", items);

        Assert.IsTrue(order.CreatedAt >= before && order.CreatedAt <= DateTime.UtcNow);
    }

    [TestMethod]
    public void CreateOrder_StoresItemsOnOrder()
    {
        var items = CreateItems(("Alpha", 2.00m, 3));

        var order = _service.CreateOrder("cust-1", items);

        Assert.AreEqual(1, order.Items.Count);
        Assert.AreEqual("Alpha", order.Items[0].ProductName);
    }

    [TestMethod]
    public void CreateOrder_WithNullCustomerId_ThrowsArgumentNullException()
    {
        var items = CreateItems(("Widget", 1.00m, 1));

        Assert.ThrowsException<ArgumentNullException>(() => _service.CreateOrder(null!, items));
    }

    [TestMethod]
    public void CreateOrder_WithNullItems_ThrowsArgumentNullException()
    {
        Assert.ThrowsException<ArgumentNullException>(() => _service.CreateOrder("cust-1", null!));
    }

    [TestMethod]
    public void CreateOrder_WithEmptyItems_ThrowsInvalidOperationException()
    {
        Assert.ThrowsException<InvalidOperationException>(() => _service.CreateOrder("cust-1", []));
    }

    // ── GetOrder ────────────────────────────────────────────────────

    [TestMethod]
    public void GetOrder_WithExistingId_ReturnsOrder()
    {
        var items = CreateItems(("Widget", 5.00m, 1));
        var created = _service.CreateOrder("cust-1", items);

        var found = _service.GetOrder(created.Id);

        Assert.IsNotNull(found);
        Assert.AreEqual(created.Id, found.Id);
    }

    [TestMethod]
    public void GetOrder_WithNonExistentId_ReturnsNull()
    {
        var result = _service.GetOrder("does-not-exist");

        Assert.IsNull(result);
    }

    // ── GetOrdersByCustomer ─────────────────────────────────────────

    [TestMethod]
    public void GetOrdersByCustomer_ReturnsAllMatchingOrders()
    {
        var items = CreateItems(("Widget", 1.00m, 1));
        _service.CreateOrder("cust-1", items);
        _service.CreateOrder("cust-1", items);
        _service.CreateOrder("cust-2", items);

        var result = _service.GetOrdersByCustomer("cust-1");

        Assert.AreEqual(2, result.Count);
        Assert.IsTrue(result.All(o => o.CustomerId == "cust-1"));
    }

    [TestMethod]
    public void GetOrdersByCustomer_WithNoOrders_ReturnsEmptyList()
    {
        var result = _service.GetOrdersByCustomer("cust-unknown");

        Assert.AreEqual(0, result.Count);
    }

    [TestMethod]
    public void GetOrdersByCustomer_DoesNotReturnOtherCustomersOrders()
    {
        var items = CreateItems(("Widget", 1.00m, 1));
        _service.CreateOrder("cust-1", items);

        var result = _service.GetOrdersByCustomer("cust-2");

        Assert.AreEqual(0, result.Count);
    }
}

